    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_inner = (N-2) * (N-2);

    if (idx >= total_inner) return;

    int i = 1 + (idx % (N-2));
    int j = 1 + (idx / (N-2));

    float t = 0.25f * (f_old[IDX(i-1,j)] +
                       f_old[IDX(i+1,j)] +
                       f_old[IDX(i,j-1)] +
