  int i, j, x, y;
  for (i = 0; Lx > i; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
       data_11[x + j*Lx] = 1.f;
  }
  for (i = 0; Ly > i; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
