  }
  memcpy(elem_22, data_11, sizeof(float)*Lx*Ly);

  for(i=0; val_26 > i; i++) {
    reference (tmp_12, elem_22, v_19, data_5, Lx, Ly);
    std::swap(tmp_12, elem_22);
