template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = 0;
  for (int64_t i = 0; i < n; i++) {
    if (ref_out[i] != out[i]) {
      error = 1;
      printf("@%zu: %lf != %lf\n", (size_t)i, (double)ref_out[i], (double)out[i]);
      break;
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernelWithConflicts(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  extern T temp_shared[N];
  T* temp = temp_shared;

  int thid = threadIdx.x;
  int num_threads = N / 2;

  T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  if (thid < num_threads) {
    temp[2*thid]   = t_in[2*thid];
    temp[2*thid+1] = t_in[2*thid+1];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1] = 0; 
  for (int d = 1; N > d; d *= 2) 
  {
    offset = offset >> (1);
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  if (thid < num_threads) {
    t_out[2*thid] = temp[2*thid];
    t_out[2*thid+1] = temp[2*thid+1];
  }
}

// Explicit specialization for template kernel with shared memory
