  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp_ptr[bi] += temp_ptr[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp_ptr[N-1] = 0; 
  for (int d = 1; N > d; d *= 2) 
  {
    offset = offset >> (1);
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp_ptr[ai];
      temp_ptr[ai] = temp_ptr[bi];
      temp_ptr[bi] += t;
    }
  }

  if (thid < num_threads) {
