    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }

  cudaMemcpy(d_out, d_in, bytes, cudaMemcpyHostToDevice); // Reset d_out to d_in for next pass if needed, though logic overwrites
  // Actually, the second kernel reads from d_in again, so no need to copy back yet.
  // But we need to copy the result of the first kernel to host for verification if not timing
  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);

  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scanKernelNoConflicts<T, N><<grid_dim, block_dim>>(d_in, d_out, grid_dim);
